#[unsafe(no_mangle)]
extern "C" fn kernel_trap_handler() -> ! {
    let scause: usize;
    let sepc: usize;
    let stval: usize;
    let sstatus: usize;
    let raw_sp: usize;
    let raw_ra: usize;
    unsafe {
        asm!("csrr {}, scause", out(reg) scause);
        asm!("csrr {}, sepc", out(reg) sepc);
        asm!("csrr {}, stval", out(reg) stval);
        asm!("csrr {}, sstatus", out(reg) sstatus);
        asm!("mv {}, sp", out(reg) raw_sp);
        asm!("mv {}, ra", out(reg) raw_ra);
    }
    console::puts("\n[KERNEL TRAP]\n");
    console::puts(" scause=0x");
    print_hex(scause);
    console::puts(" sepc=0x");
    print_hex(sepc);
    console::puts(" stval=0x");
    print_hex(stval);
    console::puts(" sstatus=0x");
    print_hex(sstatus);
    console::puts(" raw_sp=0x");
    print_hex(raw_sp);
    console::puts(" raw_ra=0x");
    print_hex(raw_ra);
    let cur = current();
    console::puts(" pid=0x");

