pub(super) fn checked_anonymous_memory_range(
    addr: usize,
    len: usize,
) -> Result<Option<(usize, usize)>, usize> {
    if addr & (PAGE_SIZE - 1) != 0 {
        return Err(linux_error(EINVAL));
    }
    if len == 0 {
        return Ok(None);
    }
    let len = checked_align_up(len).ok_or_else(|| linux_error(EINVAL))?;
    let end = addr.checked_add(len).ok_or_else(|| linux_error(EINVAL))?;
    let mut vaddr = addr;
    while vaddr < end {
        if !stage1_user_page_mapped(vaddr) {
            return Err(linux_error(ENOMEM));
        }
        vaddr += PAGE_SIZE;
    }
    Ok(Some((addr, end)))
}

